def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            base = (1 - ratio) ** 4 * 20
            score += base
            for x in range(1, 7):
                score += np.cos(ratio * x * np.pi / 2) ** 2 * x
            if capacity % 4 == 0:
                score += np.sqrt(capacity) * 1.5
        elif 0.2 <= ratio < 0.5:
            score += np.exp(-ratio) * 30
            count = 0
            for y in range(1, int(capacity) + 1):
                if capacity % y == 0 and y < item:
                    score += y * 0.07
                    count += 1
                if count > 5:
                    break
            if int(item) % 2 == 0:
                score += (item % capacity) * 2
        elif 0.5 <= ratio < 0.8:
            score += np.log1p(ratio) * 12
            for z in range(1, 5):
                val = ((ratio * z) % 1) ** 3
                score += val * 4
            if capacity > item * 2:
                for w in range(1, 4):
                    score += (w ** 2) / (capacity + 1)
        elif 0.8 <= ratio <= 1:
            sigmoid = 1 / (1 + np.exp(-15 * (ratio - 0.9)))
            score += sigmoid * 25
            substr = 0
            for n in range(1, int(capacity) + 1):
                if capacity % n == 0 and n % 3 == 0:
                    substr += np.log1p(n) * 1.8
            score += substr
        else:
            penalty = 0
            int_ratio = int(ratio)
            remainder = ratio - int_ratio
            for j in range(1, int_ratio + 2):
                if int_ratio % j == 0:
                    penalty += j * 3
            penalty += sum([(remainder ** k) * 5 for k in range(1, 5)])
            score = penalty + (ratio - 1) * 35
            if ratio > 3:
                for n in range(1, int(capacity // 3) + 2):
                    if capacity % n == 0:
                        score += np.tanh(n / (ratio + 0.5)) * 4
            if int(capacity) % 7 == 0:
                score *= 0.85
            if int(capacity) % 11 == 0 and ratio < 2:
                score *= 1.15
        if item % 1 > 0.5:
            score += np.sin(item * np.pi) * 2
        if int(capacity) % 2 == 1 and ratio < 0.5:
            score += 3
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
        priorities = np.where(np.isfinite(priorities), priorities, min_priority + 250)
    else:
        priorities = np.full_like(priorities, np.inf)
    return priorities
